  "script_content": "def calculate(inputs: dict) -> dict:
    # Default fallback values for results
    fallback_results = {
        "tip_amount": 0.0,
        "total_amount": 0.0
    }

    try:
        # Ensure we have bill_amount
        if "bill_amount" not in inputs or inputs["bill_amount"] is None:
            return {
                "error": "Invalid Input: Bill amount is required",
                **fallback_results
            }

        # Safely convert to float
        bill_amount = float(inputs["bill_amount"])

        # Handle tip_percentage (default to 0.0 if not provided)
        tip_percentage = float(inputs.get("tip_percentage", 0.0))

    except (ValueError, TypeError):
        return {
            "error": "Invalid Input: Please provide valid numbers for inputs",
            **fallback_results
        }

    # Validate non-negative bill amount
    if bill_amount < 0.0:
        return {
            "error": "Invalid Input: Bill amount must be greater than or equal to 0",
            **fallback_results
        }

    # Validate non-negative tip percentage
    if tip_percentage < 0.0:
        return {
            "error": "Invalid Input: Tip percentage cannot be negative",
            **fallback_results
        }

    # Compute tip and total
    tip_amount = bill_amount * (tip_percentage / 100.0)
    total_amount = bill_amount + tip_amount

    # Round to exactly 2 decimal places
    tip_amount_rounded = round(tip_amount, 2)
    total_amount_rounded = round(total_amount, 2)

    return {
        "tip_amount": tip_amount_rounded,
        "total_amount": total_amount_rounded
    }"
}

