{"script_content": "def calculate(inputs: dict) -> dict:
    # Initialize default result keys to handle error paths gracefully
    result = {"bmi_value": 0.0}

    try:
        # Ensure keys are present in the input dictionary
        if 'height_cm' not in inputs or 'weight_kg' not in inputs:
            return {"error": "Missing required fields: height_cm and weight_kg", "bmi_value": 0.0}

        # Cast values aggressively to float
        try:
            height_cm = float(inputs['height_cm'])
            weight_kg = float(inputs['weight_kg'])
        except (ValueError, TypeError):
            return {"error": "Invalid input type. Numeric inputs are required.", "bmi_value": 0.0}

        # Validate range values according to parameters spec
        if height_cm < 1.0 or height_cm > 300.0:
            return {"error": "Height must be between 1.0 and 300.0 cm.", "bmi_value": 0.0}
        if weight_kg < 1.0 or weight_kg > 1000.0:
            return {"error": "Weight must be between 1.0 and 1000.0 kg.", "bmi_value": 0.0}

        # Conversion and BMI computation
        height_m = height_cm / 100.0

        # Guard against potential division by zero (even though min is validated to 1.0)
        if height_m == 0.0:
            return {"error": "Height cannot be zero.", "bmi_value": 0.0}

        bmi = weight_kg / (height_m * height_m)
        result["bmi_value"] = round(bmi, 2)
        return result

    except Exception as e:
        return {"error": f"An unexpected error occurred: {str(e)}", "bmi_value": 0.0}"}

